  function refreshOwnerScopedViews(){initSelects();renderOwnerMetrics();renderDailyWork();renderOwnerCalendar();renderSixMonthStats();renderOwnerBookings();renderManualRecords();renderCleaningFinance();renderOwnerNotes();}
  function renderAdminDashboard(){const el=document.getElementById('owner');if(!el)return;const owners=userList().filter(u=>u.role==='owner'), cleaners=userList().filter(u=>u.role==='cleaner');el.innerHTML=`<div class='admin-shell'><div class='admin-panel'><h2>系统总览</h2><div class='small'>管理员看到全局后台数据。</div></div><div class='admin-metric-grid'><div class='admin-metric'><div class='small'>房东账号</div><div class='num'>${owners.length}</div></div><div class='admin-metric'><div class='small'>保洁账号</div><div class='num'>${cleaners.length}</div></div><div class='admin-metric'><div class='small'>房源</div><div class='num'>${props().length}</div></div><div class='admin-metric'><div class='small'>房间</div><div class='num'>${roomList().length}</div></div></div><div class='admin-panel'><h2>房源 / 保洁关系</h2><table class='admin-table'><tr><th>房源</th><th>房间</th><th>公区</th><th>保洁</th></tr>${props().map(p=>`<tr><td>${esc(displayPropertyName(p.name,p.id))}</td><td>${propRooms(p.id).length}</td><td>${propAreas(p.id).length}</td><td>${propCleaners(p.id).map(x=>esc(cleanerLabel(x.cleaner_code))).join('、')||'未绑定'}</td></tr>`).join('')}</table></div></div>`;}
  function bindCalendarRangeControls(){['rangeStart','rangeEnd','ownerRoomFilter'].forEach(id=>{const el=document.getElementById(id);if(el&&!el.dataset.pmsRangeBound){el.onchange=refreshCalendarRangeViews;el.dataset.pmsRangeBound='1';}});updateRangePresetButtons();}
  function suppressLegacyPropertyManagement(){document.querySelectorAll('.property-management-card').forEach(el=>el.remove());try{window.insertPropertyManagement=function(){};}catch(e){}}
  function setup(){ensureCss();suppressLegacyPropertyManagement();bindCalendarRangeControls();document.querySelectorAll('.small').forEach(el=>{const text=el.textContent||'';if(text.includes('在住房间会显示'))el.textContent='剩余在住会显示“还剩几天退房”，方便判断是否需要提前安排续住沟通、补充用品或中途清洁。';if(text.includes('黄色边框表示该房间该日期有房东备注')||text.includes('未来房态：绿色整格表示在住'))el.textContent='未来房态：绿色整格表示在住；左上绿色三角表示当天退房；右下绿色三角表示当天入住；同日退房又入住会用 / 对角线同时显示；红色表示不开放锁定；黄色边框表示有房东备注。';});const cleanerManualBtn=document.querySelector('button[onclick*="cleanerManual"]');if(cleanerManualBtn)cleanerManualBtn.textContent='历史/调整';const cleanerHistoryBtn=document.querySelector('button[onclick*="cleanerHistory"]');if(cleanerHistoryBtn)cleanerHistoryBtn.style.display='none';const cleanTab=document.querySelector('button[onclick*="ownerCleaning"]');if(cleanTab)cleanTab.textContent='保洁管理';const notesTab=document.querySelector('button[onclick*="ownerNotes"]');if(notesTab)notesTab.style.display='none';const notesSection=document.getElementById('ownerNotes');if(notesSection){notesSection.style.display='none';}const tab=document.querySelector('button[onclick*="ownerRooms"]');if(tab){tab.textContent='房源 / 房间设置';tab.setAttribute('onclick',"showOwnerTab('ownerRooms', this); backToPropertyList();");}const section=document.getElementById('ownerRooms');if(section){const card=section.querySelector(':scope > .card');if(card){const h2=card.querySelector('h2');const p=card.querySelector('p.small');const isDetail=!!activeProp();if(h2){h2.textContent=isDetail?'':'房间管理';h2.style.display=isDetail?'none':'';}if(p){p.textContent=isDetail?'':'房源的添加、改名、删除和筛选已经放到上方房源管理模块；点上方“进入房间管理”后，这里只显示该房源的房间、公区、iCal 和保洁绑定。';p.style.display=isDetail?'none':'';}card.querySelectorAll('button[onclick=\"syncIcal()\"],button[onclick=\"addRoom()\"] ,button[onclick=\"addCommonArea()\"],#syncIcalBtn').forEach(btn=>{btn.style.display='none';});}}const common=document.getElementById('commonSettings');if(common&&common.closest('.card'))common.closest('.card').style.display='none';}
  async function saveCommonAreas(btn,successText){await persistAll();renderRoomSettings();return true;}
  function renderCommonSettings(){const common=document.getElementById('commonSettings');if(common)common.innerHTML='';}
  function renderRoomSettings(){setup();if(activeProp()&&!props().some(p=>p.id===activeProp().id))setActive('');const h=document.getElementById('roomSettings');if(!h)return;if(!props().length){h.innerHTML=`<div class='empty-panel'><strong>还没有房源</strong><div class='small' style='margin-top:8px'>先在上方房源管理模块添加房源。</div></div>`;return;}const p=activeProp();h.innerHTML=p?renderPropertyDetail(p):`<div class='empty-panel'><strong>从上方房源管理进入房间管理</strong><div class='small' style='margin-top:8px'>上方已经可以完成房源筛选、添加、改名、删除；这里只在进入某个房源后显示房间、公区、iCal 和保洁绑定。</div></div>`;}
  function renderOwner(){if(current()&&current().role==='admin'){renderAdminDashboard();return;}if(props().length&&(!Array.isArray(S.ownerPropertyIds))&&!S.ownerPropertyId){saveOwnerPropIds(validPropIds());}setup();refreshOwnerScopedViews();renderRoomSettings();}
